external_knowledge:
- 'Top-performing neural networks' refers to those with average training accuracy > 0.5;
- 'Recently activated' means created after '2023-10-01 10:00:00';
- 'Rigorous training' implies multiple training sessions;
- 'Identity' corresponds to 'network_id';
- 'Overall prowess' refers to 'average_training_accuracy';
- 'Battles fought' corresponds to 'training_sessions_count'.

sql:
SELECT network_id, max_iterations, training_start_time, training_end_time, total_time
FROM trainings
WHERE training_id = 0;

SELECT architecture_name
FROM architectures
WHERE architecture_id = 0;
